"use client";

import { createContext, useContext, useMemo, ReactNode } from "react";
import { useUser } from "@/context/UserContext";
import { BETA_MODE } from "@/lib/config";

type Plan = "beta" | "pro" | "free";

interface SubscriptionContextType {
  plan: Plan;
  isBeta: boolean;
  isPro: boolean;
  hasAccess: boolean; // true if user can use the app (beta OR pro)
  isLoading: boolean;
}

const SubscriptionContext = createContext<SubscriptionContextType>({
  plan: "beta",
  isBeta: true,
  isPro: false,
  hasAccess: true,
  isLoading: true,
});

export function SubscriptionProvider({ children }: { children: ReactNode }) {
  const { profile, loading } = useUser();

  const value = useMemo<SubscriptionContextType>(() => {
    const planExpired = profile?.plan_expires_at
      ? new Date(profile.plan_expires_at) < new Date()
      : false;
    // "pro" without an expiry date is treated as free — means data is inconsistent
    const proWithoutExpiry = profile?.plan === "pro" && !profile?.plan_expires_at;
    const plan: Plan = (!profile?.plan || planExpired || proWithoutExpiry) ? "free" : (profile.plan as Plan);
    const isBeta = plan === "beta" || BETA_MODE;
    const isPro = plan === "pro";
    const hasAccess = BETA_MODE || isPro || isBeta;
    return { plan, isBeta, isPro, hasAccess, isLoading: loading };
  }, [profile, loading]);

  return (
    <SubscriptionContext.Provider value={value}>
      {children}
    </SubscriptionContext.Provider>
  );
}

export function useSubscription() {
  return useContext(SubscriptionContext);
}

"use client";

import { useState } from "react";
import { ClipboardList, AlertTriangle } from "lucide-react";
import TradingRulesInput from "@/components/organisms/TradingRulesInput";
import TradingRulesList from "@/components/organisms/TradingRulesList";
import { TradingRule } from "@/services/tradingPlanService";

type TabType = "rules" | "mistakes";

interface MyPlanSectionProps {
  rules: TradingRule[];
  mistakes: TradingRule[];
  loading: boolean;
  onAddRule: (content: string) => Promise<void>;
  onAddMistake: (content: string) => Promise<void>;
  onToggleRule: (id: string, active: boolean) => Promise<void>;
  onToggleMistake: (id: string, active: boolean) => Promise<void>;
  onDeleteRule: (id: string) => Promise<void>;
  onDeleteMistake: (id: string) => Promise<void>;
}

export default function MyPlanSection({
  rules,
  mistakes,
  loading,
  onAddRule,
  onAddMistake,
  onToggleRule,
  onToggleMistake,
  onDeleteRule,
  onDeleteMistake,
}: MyPlanSectionProps) {
  const [activeTab, setActiveTab] = useState<TabType>("rules");

  return (
    <>
      {/* Header */}
      <div className="rounded-lg border border-emerald-700/50 bg-emerald-900/20 p-4 md:p-6 mb-4 md:mb-6">
        <h1 className="text-2xl md:text-3xl font-bold text-white mb-1 md:mb-2">Trading Plan</h1>
        <p className="text-slate-300 text-sm md:text-base mb-2 md:mb-3">
          Your strategy guide to trade with discipline, not emotions
        </p>
        <div className="bg-slate-900/50 rounded-md p-3 md:p-4 border border-slate-700">
          <p className="text-xs md:text-sm text-emerald-400 font-semibold mb-1.5 md:mb-2">
            ⚡ Before every trade, check:
          </p>
          <ul className="text-xs md:text-sm text-slate-300 space-y-0.5 md:space-y-1 ml-4 md:ml-5 list-disc">
            <li>Am I following my Trading Rules?</li>
            <li>Am I avoiding my common Mistakes?</li>
            <li>Is this trade part of my strategy or an emotional decision?</li>
          </ul>
        </div>
      </div>

      {/* Tabs Navigation - Hidden on Desktop for Rules/Mistakes */}
      <div className="md:hidden flex gap-2 border-b border-slate-700 mb-3 overflow-x-auto">
        <TabButton
          icon={<ClipboardList className="w-4 h-4" />}
          label="Trading Rules"
          active={activeTab === "rules"}
          color="emerald"
          onClick={() => setActiveTab("rules")}
        />
        <TabButton
          icon={<AlertTriangle className="w-4 h-4" />}
          label="My Mistakes"
          active={activeTab === "mistakes"}
          color="red"
          onClick={() => setActiveTab("mistakes")}
        />
      </div>

      {/* Desktop Sidebar Navigation - Hidden on Mobile */}
      <div className="hidden md:flex gap-2 border-b border-slate-700 mb-6 overflow-x-auto">
        <TabButton
          icon={<ClipboardList className="w-4 h-4" />}
          label="Trading Rules & Mistakes"
          active={activeTab === "rules" || activeTab === "mistakes"}
          color="emerald"
          onClick={() => setActiveTab("rules")}
        />
      </div>

      {/* Mobile: Tab Content (Stacked) */}
      <div className="md:hidden">
        {activeTab === "rules" && (
          <RulesTab
            rules={rules}
            loading={loading}
            onAdd={onAddRule}
            onToggle={onToggleRule}
            onDelete={onDeleteRule}
          />
        )}

        {activeTab === "mistakes" && (
          <MistakesTab
            mistakes={mistakes}
            loading={loading}
            onAdd={onAddMistake}
            onToggle={onToggleMistake}
            onDelete={onDeleteMistake}
          />
        )}
      </div>

      {/* Desktop: Rules & Mistakes Side by Side */}
      <div className="hidden md:grid md:grid-cols-2 gap-6">
        <RulesTab
          rules={rules}
          loading={loading}
          onAdd={onAddRule}
          onToggle={onToggleRule}
          onDelete={onDeleteRule}
        />
        <MistakesTab
          mistakes={mistakes}
          loading={loading}
          onAdd={onAddMistake}
          onToggle={onToggleMistake}
          onDelete={onDeleteMistake}
        />
      </div>
    </>
  );
}

// ============================================
// Tab Components
// ============================================

function TabButton({
  icon,
  label,
  active,
  color,
  onClick,
}: {
  icon: React.ReactNode;
  label: string;
  active: boolean;
  color: string;
  onClick: () => void;
}) {
  const borderColor = active
    ? `border-${color}-500`
    : "border-transparent";
  const textColor = active
    ? `text-${color}-400`
    : "text-slate-400 hover:text-slate-300";

  return (
    <button
      onClick={onClick}
      className={`flex items-center gap-2 px-4 py-3 font-semibold transition-all whitespace-nowrap border-b-2 ${borderColor} ${textColor}`}
    >
      {icon}
      {label}
    </button>
  );
}

function RulesTab({
  rules,
  loading,
  onAdd,
  onToggle,
  onDelete,
}: {
  rules: TradingRule[];
  loading: boolean;
  onAdd: (content: string) => Promise<void>;
  onToggle: (id: string, active: boolean) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
}) {
  return (
    <div className="rounded-lg border border-emerald-700 bg-slate-800 p-4 md:p-6 shadow-xl">
      <div className="flex items-start gap-2 mb-3 md:mb-4">
        <div className="bg-emerald-500/20 p-1.5 md:p-2 rounded-lg shrink-0">
          <span className="text-xl md:text-2xl">✅</span>
        </div>
        <div>
          <h2 className="text-lg md:text-xl font-semibold text-white mb-0.5 md:mb-1">Trading Rules</h2>
          <p className="text-xs text-slate-400">
            Define your must-follow rules before entering any trade
          </p>
        </div>
      </div>

      <TradingRulesInput
        onAdd={onAdd}
        placeholder="e.g., Follow market trend…"
        isLoading={loading}
      />

      <div className="mt-4 md:mt-6">
        <TradingRulesList
          rules={rules}
          onToggle={onToggle}
          onDelete={onDelete}
          isLoading={loading}
        />
      </div>
    </div>
  );
}

function MistakesTab({
  mistakes,
  loading,
  onAdd,
  onToggle,
  onDelete,
}: {
  mistakes: TradingRule[];
  loading: boolean;
  onAdd: (content: string) => Promise<void>;
  onToggle: (id: string, active: boolean) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
}) {
  return (
    <div className="rounded-lg border border-red-700 bg-slate-800 p-4 md:p-6 shadow-xl">
      <div className="flex items-start gap-2 mb-3 md:mb-4">
        <div className="bg-red-500/20 p-1.5 md:p-2 rounded-lg shrink-0">
          <span className="text-xl md:text-2xl">⚠️</span>
        </div>
        <div>
          <h2 className="text-lg md:text-xl font-semibold text-white mb-0.5 md:mb-1">My Trading Mistakes</h2>
          <p className="text-xs text-slate-400">
            Track mistakes you tend to make when trading emotionally
          </p>
        </div>
      </div>

      <TradingRulesInput
        onAdd={onAdd}
        placeholder="e.g., Revenge trading…"
        isLoading={loading}
      />

      <div className="mt-4 md:mt-6">
        <TradingRulesList
          rules={mistakes}
          onToggle={onToggle}
          onDelete={onDelete}
          isLoading={loading}
        />
      </div>
    </div>
  );
}

/**
 * Global app configuration constants.
 * BETA_MODE: when true, all authenticated users bypass the subscription gate.
 * Set NEXT_PUBLIC_BETA_MODE=false in env to enforce payment.
 */
export const BETA_MODE = process.env.NEXT_PUBLIC_BETA_MODE !== "false";

export const PADDLE_CLIENT_TOKEN = process.env.NEXT_PUBLIC_PADDLE_CLIENT_TOKEN ?? "";
export const PADDLE_PRICE_ID = process.env.NEXT_PUBLIC_PADDLE_PRICE_ID ?? "";
export const PADDLE_YEARLY_PRICE_ID = process.env.NEXT_PUBLIC_PADDLE_YEARLY_PRICE_ID ?? "";

// Monthly plan pricing
export const PLAN_PRICE_USD = 18;
export const PLAN_ORIGINAL_USD = 29;
export const PLAN_DISCOUNT_PCT = Math.round(
  ((PLAN_ORIGINAL_USD - PLAN_PRICE_USD) / PLAN_ORIGINAL_USD) * 100
); // 38

// Yearly plan pricing ($8.25/mo billed as $99/year)
export const PLAN_PRICE_YEARLY_TOTAL = 99;
export const PLAN_PRICE_YEARLY_MONTHLY = Math.round((99 / 12) * 100) / 100; // 8.25
// Savings % vs the monthly price (18 �+' 8.25 = 54%)
export const PLAN_DISCOUNT_YEARLY_PCT = Math.round(
  ((PLAN_PRICE_USD - PLAN_PRICE_YEARLY_MONTHLY) / PLAN_PRICE_USD) * 100
); // 54

// Free trial
export const TRIAL_DAYS = 7;

