import { apiClient } from "@/lib/api/apiClient";

export interface UserProfile {
  id: string;
  first_name: string | null;
  last_name: string | null;
  avatar_url: string | null;
  bio: string | null;
  plan: string | null;
  plan_expires_at: string | null;
  created_at: string;
  updated_at: string;
}

/**
 * Get user profile
 */
export const getUserProfile = async (userId: string): Promise<UserProfile | null> => {
  try {
    const data = await apiClient.getOne<UserProfile>("user_profiles", userId);
    return data || null;
  } catch (error) {
    console.error("Error fetching user profile:", error);
    return null;
  }
};

/**
 * Create user profile
 */
export const createUserProfile = async (
  userId: string,
  firstName: string,
  lastName: string = ""
): Promise<UserProfile | null> => {
  try {
    const profile = await apiClient.create<UserProfile>("user_profiles", {
      id: userId,
      first_name: firstName.trim(),
      last_name: lastName.trim() || null,
    });
    return profile;
  } catch (error) {
    console.error("Error creating user profile:", error);
    return null;
  }
};

/**
 * Update user profile
 */
export const updateUserProfile = async (
  userId: string,
  updates: Partial<UserProfile>
): Promise<UserProfile | null> => {
  try {
    const profile = await apiClient.patch<UserProfile>("user_profiles", userId, updates);
    return profile;
  } catch (error) {
    console.error("Error updating user profile:", error);
    return null;
  }
};

/**
 * Check if user profile exists
 */
export const checkProfileExists = async (userId: string): Promise<boolean> => {
  try {
    const profile = await getUserProfile(userId);
    return profile !== null;
  } catch (error) {
    console.error("Error checking profile existence:", error);
    return false;
  }
};

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import Image from "next/image";
import {
  X, TrendingUp, TrendingDown, BarChart2, Wallet, Target, ChevronRight, Layers, EyeOff,
} from "lucide-react";
import { supabase } from "@/lib/supabase/client";
import { useUser } from "@/context/UserContext";
import { useAccount } from "@/context/AccountContext";
import { useBalance } from "@/context/BalanceContext";
import { useOnboarding } from "@/context/OnboardingContext";
import { TradingAccount } from "@/services/accountService";

// ── Types ──────────────────────────────────────────────────────────────────────

interface TimeSeries { date: string; cumulativePL: number }

interface AccountMetrics {
  totalPL: number;
  winRate: number;
  totalTrades: number;
  totalWins: number;
  sumWins: number;
  sumLosses: number;
  maxDrawdown: number;
  bestTrade: number;
  worstTrade: number;
  netTransactions: number;
  balance: number;
  timeSeries: TimeSeries[];
}

interface ProfilePanelProps {
  open: boolean;
  onClose: () => void;
}

// ── Raw money formatter (always shows value, used with blur) ──────────────────

function rawFmt(n: number, opts?: { decimals?: number; sign?: boolean }): string {
  const d = opts?.decimals ?? 2;
  const abs = Math.abs(n).toLocaleString("en-US", { minimumFractionDigits: d, maximumFractionDigits: d });
  const prefix = opts?.sign && n >= 0 ? "+" : n < 0 ? "-" : "";
  return `${prefix}$${abs}`;
}

// ── Data fetch ─────────────────────────────────────────────────────────────────

async function fetchAccountMetrics(
  userId: string,
  account: TradingAccount
): Promise<AccountMetrics> {
  const [entriesRes, txRes] = await Promise.all([
    supabase
      .from("journal_entries")
      .select("profit_loss, exit_price, entry_price, quantity, type, date")
      .eq("user_id", userId)
      .eq("account_id", account.id)
      .eq("status", "closed")
      .order("date", { ascending: true }),
    supabase
      .from("account_transactions")
      .select("type, amount")
      .eq("account_id", account.id),
  ]);

  const closed = entriesRes.data || [];
  const txs    = txRes.data    || [];

  const getPL = (e: typeof closed[0]) => {
    if (e.profit_loss != null) return Number(e.profit_loss);
    if (e.exit_price && e.entry_price && e.quantity)
      return e.type === "long"
        ? (e.exit_price - e.entry_price) * e.quantity
        : (e.entry_price - e.exit_price) * e.quantity;
    return 0;
  };

  const pls       = closed.map(getPL);
  const totalPL   = pls.reduce((s, v) => s + v, 0);
  const winPLs    = pls.filter(v => v > 0);
  const lossPLs   = pls.filter(v => v < 0);
  const sumWins   = winPLs.reduce((s, v) => s + v, 0);
  const sumLosses = Math.abs(lossPLs.reduce((s, v) => s + v, 0));
  const bestTrade  = pls.length > 0 ? Math.max(...pls) : 0;
  const worstTrade = pls.length > 0 ? Math.min(...pls) : 0;

  let maxDD = 0, peak = 0, run = 0;
  pls.forEach(pl => {
    run += pl;
    if (run > peak) peak = run;
    const dd = peak - run;
    if (dd > maxDD) maxDD = dd;
  });

  const netTransactions = txs.reduce(
    (s, tx) => s + (tx.type === "deposit" ? Number(tx.amount) : -Number(tx.amount)), 0
  );

  const byDate = new Map<string, number>();
  closed.forEach((e) => {
    const day = (e.date || "").split("T")[0];
    if (day) byDate.set(day, (byDate.get(day) || 0) + getPL(e));
  });
  let cum = 0;
  const timeSeries: TimeSeries[] = Array.from(byDate.keys()).sort().map((date) => {
    cum += byDate.get(date) || 0;
    return { date, cumulativePL: cum };
  });

  return {
    totalPL,
    winRate: closed.length > 0 ? (winPLs.length / closed.length) * 100 : 0,
    totalTrades: closed.length,
    totalWins: winPLs.length,
    sumWins,
    sumLosses,
    maxDrawdown: maxDD,
    bestTrade,
    worstTrade,
    netTransactions,
    balance: account.initial_capital + netTransactions + totalPL,
    timeSeries,
  };
}

// ── SVG helpers ────────────────────────────────────────────────────────────────

function linePath(pts: { x: number; y: number }[]): string {
  if (pts.length === 0) return "";
  return pts.map((p, i) => `${i === 0 ? "M" : "L"} ${p.x.toFixed(1)} ${p.y.toFixed(1)}`).join(" ");
}

function fmtLabel(v: number) {
  const abs = Math.abs(v);
  if (abs >= 1000) return `${v < 0 ? "-" : ""}$${(abs / 1000).toFixed(1)}k`;
  return `${v < 0 ? "-" : ""}$${abs.toFixed(0)}`;
}

function fmtDate(d: string) {
  return new Date(d + "T00:00:00").toLocaleDateString("en-US", { month: "short", day: "numeric" });
}

// ── Equity chart ───────────────────────────────────────────────────────────────

function EquityChart({
  accounts,
  metricsMap,
}: {
  accounts: TradingAccount[];
  metricsMap: Record<string, AccountMetrics>;
}) {
  const VW = 500; const VH = 190;
  const pad = { t: 12, r: 10, b: 34, l: 46 };
  const cw = VW - pad.l - pad.r;
  const ch = VH - pad.t - pad.b;

  const allDatesSet = new Set<string>();
  accounts.forEach((a) => metricsMap[a.id]?.timeSeries.forEach((p) => allDatesSet.add(p.date)));
  const allDates = Array.from(allDatesSet).sort();

  if (allDates.length === 0) {
    return (
      <div className="flex items-center justify-center h-24 text-slate-600 text-[10px]">
        No closed trades yet
      </div>
    );
  }

  const toX = (d: string) => pad.l + (allDates.indexOf(d) / Math.max(allDates.length - 1, 1)) * cw;

  const combinedByDate = new Map<string, number>();
  accounts.forEach((a) => {
    const ts = metricsMap[a.id]?.timeSeries || [];
    ts.forEach((p, i) => {
      const delta = i === 0 ? p.cumulativePL : p.cumulativePL - ts[i - 1].cumulativePL;
      combinedByDate.set(p.date, (combinedByDate.get(p.date) || 0) + delta);
    });
  });
  let cumRun = 0;
  const combinedSeries: TimeSeries[] = allDates.map((date) => {
    cumRun += combinedByDate.get(date) || 0;
    return { date, cumulativePL: cumRun };
  });

  const allVals = [0, ...combinedSeries.map((p) => p.cumulativePL)];
  accounts.forEach((a) => metricsMap[a.id]?.timeSeries.forEach((p) => allVals.push(p.cumulativePL)));
  const minV = Math.min(...allVals);
  const maxV = Math.max(...allVals);
  const range = maxV - minV || 1;
  const toY = (v: number) => pad.t + ch - ((v - minV) / range) * ch;
  const zeroY = toY(0);
  const showCombined = accounts.length > 1;

  const gridVals = [0, 1, 2, 3].map((i) => minV + (range / 3) * (3 - i));
  const step = Math.max(1, Math.floor(allDates.length / 4));
  const xLabels = allDates.filter((_, i) => i % step === 0 || i === allDates.length - 1);

  const combPts = combinedSeries.map((p) => ({ x: toX(p.date), y: toY(p.cumulativePL) }));
  const combLine = linePath(combPts);
  const lastCombPt = combPts[combPts.length - 1];
  const firstCombPt = combPts[0];
  const combArea = combLine
    ? `${combLine} L ${lastCombPt.x.toFixed(1)} ${zeroY.toFixed(1)} L ${firstCombPt.x.toFixed(1)} ${zeroY.toFixed(1)} Z`
    : "";

  return (
    <svg width="100%" height="160" viewBox={`0 0 ${VW} ${VH}`} preserveAspectRatio="xMidYMid meet">
      <defs>
        <linearGradient id="combGradEq" x1="0" x2="0" y1="0" y2="1">
          <stop offset="0%" stopColor="rgba(255,255,255,0.12)" />
          <stop offset="100%" stopColor="rgba(255,255,255,0.01)" />
        </linearGradient>
        {accounts.map((a) => (
          <linearGradient key={a.id} id={`eqGrad-${a.id.slice(0, 8)}`} x1="0" x2="0" y1="0" y2="1">
            <stop offset="0%" stopColor={a.color} stopOpacity="0.25" />
            <stop offset="100%" stopColor={a.color} stopOpacity="0.01" />
          </linearGradient>
        ))}
      </defs>

      {gridVals.map((v, i) => (
        <g key={i}>
          <line x1={pad.l} y1={toY(v)} x2={pad.l + cw} y2={toY(v)} stroke="#1e293b" strokeWidth="1" />
          <text x={pad.l - 4} y={toY(v) + 3.5} textAnchor="end" fontSize="9" fill="#475569" fontFamily="monospace">
            {fmtLabel(v)}
          </text>
        </g>
      ))}

      {minV < 0 && maxV > 0 && (
        <line x1={pad.l} y1={zeroY} x2={pad.l + cw} y2={zeroY}
          stroke="#334155" strokeWidth="1" strokeDasharray="3 2" />
      )}

      {showCombined && combPts.length > 1 && (
        <g>
          <path d={combArea} fill="url(#combGradEq)" />
          <path d={combLine} fill="none" stroke="rgba(255,255,255,0.22)"
            strokeWidth="1.5" strokeDasharray="4 3" strokeLinecap="round" />
        </g>
      )}

      {accounts.map((a) => {
        const ts = metricsMap[a.id]?.timeSeries || [];
        if (ts.length < 1) return null;
        const pts = ts.map((p) => ({ x: toX(p.date), y: toY(p.cumulativePL) }));
        const lp = linePath(pts);
        if (ts.length >= 2) {
          const last = pts[pts.length - 1]; const first = pts[0];
          const area = `${lp} L ${last.x.toFixed(1)} ${zeroY.toFixed(1)} L ${first.x.toFixed(1)} ${zeroY.toFixed(1)} Z`;
          return (
            <g key={a.id}>
              <path d={area} fill={`url(#eqGrad-${a.id.slice(0, 8)})`} />
              <path d={lp} fill="none" stroke={a.color} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />
            </g>
          );
        }
        const last = ts[ts.length - 1];
        return <circle key={a.id} cx={toX(last.date)} cy={toY(last.cumulativePL)} r="5" fill={a.color} stroke="#0f172a" strokeWidth="2" />;
      })}

      {accounts.map((a) => {
        const ts = metricsMap[a.id]?.timeSeries || [];
        if (ts.length < 2) return null;
        const last = ts[ts.length - 1];
        return (
          <circle key={`dot-${a.id}`} cx={toX(last.date)} cy={toY(last.cumulativePL)}
            r="3.5" fill={a.color} stroke="#0f172a" strokeWidth="1.5">
            <title>{a.name}: ${last.cumulativePL.toFixed(2)}</title>
          </circle>
        );
      })}

      {xLabels.map((d) => (
        <text key={`xl-${d}`} x={toX(d)} y={VH - 6} textAnchor="middle" fontSize="9" fill="#475569">
          {fmtDate(d)}
        </text>
      ))}
    </svg>
  );
}

// ── Account detail panel ───────────────────────────────────────────────────────

function AccountDetailPanel({
  account,
  m,
}: {
  account: TradingAccount;
  m: AccountMetrics;
}) {
  const { showBalance, fmtMoney } = useBalance();

  const b = !showBalance; // shorthand: "blurred"
  const losses  = m.totalTrades - m.totalWins;
  const pf      = m.sumLosses > 0 ? m.sumWins / m.sumLosses : m.sumWins > 0 ? 999 : 0;
  const exp     = m.totalTrades > 0 ? m.totalPL / m.totalTrades : 0;
  const avgWin  = m.totalWins > 0 ? m.sumWins / m.totalWins : 0;
  const avgLoss = losses > 0 ? m.sumLosses / losses : 0;

  const pfColor  = pf >= 2 ? "text-emerald-400" : pf >= 1 ? "text-amber-400" : "text-red-400";
  const expColor = exp >= 0 ? "text-emerald-400" : "text-red-400";

  // Each stat: label, raw value string, color class, blurred (money vs ratio)
  const statRows = [
    [
      { label: "Profit Factor", value: pf === 999 ? "∞" : pf.toFixed(2),                        color: pfColor,           money: false },
      { label: "Expectancy",    value: b ? rawFmt(exp, { sign: true }) : fmtMoney(exp, { sign: true }), color: expColor, money: true  },
      { label: "Max Drawdown",  value: m.maxDrawdown > 0 ? (b ? rawFmt(-m.maxDrawdown) : fmtMoney(-m.maxDrawdown)) : "—", color: "text-amber-400", money: m.maxDrawdown > 0 },
    ],
    [
      { label: "Avg Win",    value: avgWin  > 0 ? (b ? rawFmt(avgWin, { sign: true })  : fmtMoney(avgWin, { sign: true }))  : "—", color: "text-emerald-400", money: avgWin  > 0 },
      { label: "Avg Loss",   value: avgLoss > 0 ? (b ? rawFmt(-avgLoss)                 : fmtMoney(-avgLoss))                 : "—", color: "text-red-400",    money: avgLoss > 0 },
      { label: "Win Rate",   value: `${m.winRate.toFixed(0)}%`,  color: "text-white",  money: false },
    ],
    [
      { label: "Best Trade",   value: m.totalTrades > 0 ? (b ? rawFmt(m.bestTrade, { sign: true }) : fmtMoney(m.bestTrade, { sign: true })) : "—", color: "text-emerald-400", money: m.totalTrades > 0 },
      { label: "Worst Trade",  value: m.totalTrades > 0 ? (b ? rawFmt(m.worstTrade, { sign: true }) : fmtMoney(m.worstTrade, { sign: true })) : "—", color: "text-red-400", money: m.totalTrades > 0 },
      { label: "Total Trades", value: `${m.totalTrades}`, color: "text-white", money: false },
    ],
  ];

  return (
    <div className="h-full flex flex-col px-5 py-4 space-y-4">
      {/* Account identity + summary numbers */}
      <div className="flex items-center gap-2.5 shrink-0">
        <span className="w-3 h-3 rounded-full shrink-0" style={{ backgroundColor: account.color }} />
        <span className="text-base font-bold text-white">{account.name}</span>
        <span className="text-xs text-slate-500">{account.currency}</span>
        <div className="ml-auto flex items-center gap-4">
          <div className="text-right">
            <p className="text-[9px] text-slate-600 uppercase tracking-wider">Balance</p>
            <p className={`text-sm font-black tabular-nums ${m.balance >= 0 ? "text-white" : "text-red-400"} ${b ? "blur-sm select-none" : ""}`}>
              {b ? rawFmt(m.balance) : fmtMoney(m.balance)}
            </p>
          </div>
          <div className="text-right">
            <p className="text-[9px] text-slate-600 uppercase tracking-wider">P&L</p>
            <p className={`text-sm font-black tabular-nums ${m.totalPL >= 0 ? "text-emerald-400" : "text-red-400"} ${b ? "blur-sm select-none" : ""}`}>
              {b ? rawFmt(m.totalPL, { sign: true }) : fmtMoney(m.totalPL, { sign: true })}
            </p>
          </div>
        </div>
      </div>

      {/* Equity chart */}
      <div className="shrink-0 rounded-xl bg-slate-800/50 border border-slate-700/40 px-3 pt-3 pb-2">
        <p className="text-[9px] font-bold uppercase tracking-widest text-slate-600 mb-2 flex items-center gap-1.5">
          <TrendingUp className="h-3 w-3" /> Equity Progression
        </p>
        {b ? (
          <div className="flex flex-col items-center justify-center h-40 gap-2">
            <EyeOff className="h-8 w-8 text-slate-700" strokeWidth={1.5} />
            <p className="text-[10px] text-slate-600 uppercase tracking-widest">Balance hidden</p>
          </div>
        ) : (
          <EquityChart accounts={[account]} metricsMap={{ [account.id]: m }} />
        )}
      </div>

      {/* Metrics grid */}
      {m.totalTrades > 0 ? (
        <div className="flex-1 space-y-2">
          {statRows.map((row, ri) => (
            <div key={ri} className="grid grid-cols-3 gap-2">
              {row.map(({ label, value, color, money }) => (
                <div key={label} className="bg-slate-800/70 rounded-xl px-3 py-2.5">
                  <p className="text-[9px] text-slate-500 uppercase tracking-wider mb-1 truncate">{label}</p>
                  <p className={`text-sm font-black tabular-nums ${color} ${b && money ? "blur-sm select-none" : ""}`}>
                    {value}
                  </p>
                </div>
              ))}
            </div>
          ))}
          {(account.initial_capital > 0 || m.netTransactions !== 0) && (
            <div className="flex items-center gap-3 px-1 pt-1">
              <Wallet className="h-3 w-3 text-slate-700 shrink-0" />
              <span className="text-[10px] text-slate-600">
                Start:{" "}
                <span className={`text-slate-500 ${b ? "blur-sm select-none" : ""}`}>
                  {b ? rawFmt(account.initial_capital) : fmtMoney(account.initial_capital)}
                </span>
              </span>
              {m.netTransactions !== 0 && (
                <span className="text-[10px] text-slate-600">
                  D/W:{" "}
                  <span className={`${m.netTransactions >= 0 ? "text-emerald-500/60" : "text-red-500/60"} ${b ? "blur-sm select-none" : ""}`}>
                    {b ? rawFmt(m.netTransactions, { sign: true }) : fmtMoney(m.netTransactions, { sign: true })}
                  </span>
                </span>
              )}
            </div>
          )}
        </div>
      ) : (
        <div className="flex-1 flex items-center justify-center">
          <p className="text-slate-600 text-sm">No closed trades yet</p>
        </div>
      )}
    </div>
  );
}

// ── Portfolio overview panel ───────────────────────────────────────────────────

function PortfolioOverviewPanel({
  accounts,
  metricsMap,
}: {
  accounts: TradingAccount[];
  metricsMap: Record<string, AccountMetrics>;
}) {
  const { showBalance, fmtMoney } = useBalance();
  const b = !showBalance;
  const valid = accounts.filter((a) => metricsMap[a.id]);

  const totalTrades  = valid.reduce((s, a) => s + metricsMap[a.id].totalTrades, 0);
  const totalWins    = valid.reduce((s, a) => s + metricsMap[a.id].totalWins, 0);
  const sumWins      = valid.reduce((s, a) => s + metricsMap[a.id].sumWins, 0);
  const sumLosses    = valid.reduce((s, a) => s + metricsMap[a.id].sumLosses, 0);
  const totalPL      = valid.reduce((s, a) => s + metricsMap[a.id].totalPL, 0);
  const totalLosses  = totalTrades - totalWins;
  const totalBalance = valid.reduce((s, a) => s + metricsMap[a.id].balance, 0);
  const winRate      = totalTrades > 0 ? (totalWins / totalTrades) * 100 : 0;

  const pf      = sumLosses > 0 ? sumWins / sumLosses : sumWins > 0 ? 999 : 0;
  const exp     = totalTrades > 0 ? totalPL / totalTrades : 0;
  const avgWin  = totalWins > 0 ? sumWins / totalWins : 0;
  const avgLoss = totalLosses > 0 ? sumLosses / totalLosses : 0;

  const pfColor  = pf >= 2 ? "text-emerald-400" : pf >= 1 ? "text-amber-400" : "text-red-400";
  const expColor = exp >= 0 ? "text-emerald-400" : "text-red-400";

  return (
    <div className="h-full flex flex-col px-5 py-4 space-y-4">
      {/* Header */}
      <div className="flex items-center gap-3 shrink-0">
        <Layers className="h-3.5 w-3.5 text-slate-500" />
        <p className="text-[10px] font-bold uppercase tracking-widest text-slate-500">All Accounts</p>
        <div className="ml-auto flex items-center gap-4">
          <div className="text-right">
            <p className="text-[9px] text-slate-600 uppercase tracking-wider">Total P&L</p>
            <p className={`text-sm font-black tabular-nums ${totalPL >= 0 ? "text-emerald-400" : "text-red-400"} ${b ? "blur-sm select-none" : ""}`}>
              {b ? rawFmt(totalPL, { sign: true }) : fmtMoney(totalPL, { sign: true })}
            </p>
          </div>
          <div className="text-right">
            <p className="text-[9px] text-slate-600 uppercase tracking-wider">Balance</p>
            <p className={`text-sm font-black tabular-nums text-white ${b ? "blur-sm select-none" : ""}`}>
              {b ? rawFmt(totalBalance) : fmtMoney(totalBalance)}
            </p>
          </div>
        </div>
      </div>

      {/* Combined equity chart */}
      <div className="shrink-0 rounded-xl bg-slate-800/50 border border-slate-700/40 px-3 pt-3 pb-2">
        <p className="text-[9px] font-bold uppercase tracking-widest text-slate-600 mb-2 flex items-center gap-1.5">
          <TrendingUp className="h-3 w-3" /> Combined Equity
        </p>
        {b ? (
          <div className="flex flex-col items-center justify-center h-40 gap-2">
            <EyeOff className="h-8 w-8 text-slate-700" strokeWidth={1.5} />
            <p className="text-[10px] text-slate-600 uppercase tracking-widest">Balance hidden</p>
          </div>
        ) : (
          <EquityChart accounts={valid} metricsMap={metricsMap} />
        )}
        <div className="flex flex-wrap gap-x-3 gap-y-1 px-1 pb-2 mt-1">
          {valid.length > 1 && (
            <div className="flex items-center gap-1.5">
              <svg width="14" height="6">
                <line x1="0" y1="3" x2="14" y2="3" stroke="rgba(255,255,255,0.22)"
                  strokeWidth="1.5" strokeDasharray="4 2" />
              </svg>
              <span className="text-[9px] text-slate-600">Combined</span>
            </div>
          )}
          {valid.map((a) => (
            <div key={a.id} className="flex items-center gap-1.5">
              <span className="w-3 h-0.5 rounded-full inline-block" style={{ backgroundColor: a.color }} />
              <span className="text-[9px] text-slate-500">{a.name}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Aggregated metrics */}
      {totalTrades > 0 && (
        <div className="flex-1 space-y-2">
          <div className="grid grid-cols-3 gap-2">
            <div className="bg-slate-800/70 rounded-xl px-3 py-2.5">
              <p className="text-[9px] text-slate-500 uppercase tracking-wider mb-1">Win Rate</p>
              <p className="text-sm font-black tabular-nums text-white">{winRate.toFixed(0)}%</p>
            </div>
            <div className="bg-slate-800/70 rounded-xl px-3 py-2.5">
              <p className="text-[9px] text-slate-500 uppercase tracking-wider mb-1">Profit Factor</p>
              <p className={`text-sm font-black tabular-nums ${pfColor}`}>{pf === 999 ? "∞" : pf.toFixed(2)}</p>
            </div>
            <div className="bg-slate-800/70 rounded-xl px-3 py-2.5">
              <p className="text-[9px] text-slate-500 uppercase tracking-wider mb-1">Expectancy</p>
              <p className={`text-sm font-black tabular-nums ${expColor} ${b ? "blur-sm select-none" : ""}`}>
                {b ? rawFmt(exp, { sign: true }) : fmtMoney(exp, { sign: true })}
              </p>
            </div>
          </div>
          <div className="grid grid-cols-3 gap-2">
            <div className="bg-slate-800/70 rounded-xl px-3 py-2.5">
              <p className="text-[9px] text-slate-500 uppercase tracking-wider mb-1">Avg Win</p>
              <p className={`text-sm font-black tabular-nums text-emerald-400 ${b && avgWin > 0 ? "blur-sm select-none" : ""}`}>
                {avgWin > 0 ? (b ? rawFmt(avgWin, { sign: true }) : fmtMoney(avgWin, { sign: true })) : "—"}
              </p>
            </div>
            <div className="bg-slate-800/70 rounded-xl px-3 py-2.5">
              <p className="text-[9px] text-slate-500 uppercase tracking-wider mb-1">Avg Loss</p>
              <p className={`text-sm font-black tabular-nums text-red-400 ${b && avgLoss > 0 ? "blur-sm select-none" : ""}`}>
                {avgLoss > 0 ? (b ? rawFmt(-avgLoss) : fmtMoney(-avgLoss)) : "—"}
              </p>
            </div>
            <div className="bg-slate-800/70 rounded-xl px-3 py-2.5">
              <p className="text-[9px] text-slate-500 uppercase tracking-wider mb-1">Total Trades</p>
              <p className="text-sm font-black tabular-nums text-white">{totalTrades}</p>
            </div>
          </div>
        </div>
      )}

      {totalTrades === 0 && (
        <div className="flex-1 flex items-center justify-center">
          <p className="text-slate-600 text-sm text-center">No closed trades yet</p>
        </div>
      )}
    </div>
  );
}

// ── Main component ─────────────────────────────────────────────────────────────

export default function ProfilePanel({ open, onClose }: ProfilePanelProps) {
  const { user, profile } = useUser();
  const { accounts } = useAccount();
  const { showBalance, fmtMoney } = useBalance();
  const { resetTour } = useOnboarding();
  const router = useRouter();
  const [metricsMap, setMetricsMap] = useState<Record<string, AccountMetrics>>({});
  const [loading, setLoading]       = useState(false);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [mobileTab, setMobileTab]   = useState<"accounts" | "detail">("accounts");

  const b = !showBalance;

  useEffect(() => {
    if (!open || !user || accounts.length === 0) return;
    setLoading(true);
    Promise.all(accounts.map((a) => fetchAccountMetrics(user.id, a).then((m) => [a.id, m] as const)))
      .then((pairs) => {
        setMetricsMap(Object.fromEntries(pairs));
        // Single account: auto-select
        if (accounts.length === 1) setSelectedId(accounts[0].id);
      })
      .finally(() => setLoading(false));
  }, [open, user, accounts]);

  useEffect(() => {
    if (!open) {
      setMobileTab("accounts");
      setSelectedId(accounts.length === 1 ? accounts[0]?.id ?? null : null);
    }
  }, [open, accounts]);

  if (!user) return null;

  const { email, user_metadata } = user;
  let fullName = "Trader";
  if (profile?.first_name)
    fullName = `${profile.first_name}${profile.last_name ? ` ${profile.last_name}` : ""}`;
  else if (user_metadata?.full_name || user_metadata?.name)
    fullName = user_metadata.full_name || user_metadata.name;
  else if (email) fullName = email.split("@")[0];
  const avatarUrl = user_metadata?.avatar_url || user_metadata?.picture;

  const allMetrics     = Object.values(metricsMap);
  const portfolioPL    = allMetrics.reduce((s, m) => s + m.totalPL, 0);
  const portfolioBalance = allMetrics.reduce((s, m) => s + m.balance, 0);

  const handleSelect = (id: string) => {
    // Multi-account: toggle (deselect → portfolio view); single account: always selected
    const next = selectedId === id && accounts.length > 1 ? null : id;
    setSelectedId(next);
    setMobileTab("detail");
  };

  // ── Loading spinner ────────────────────────────────────────────────────────
  const loadingSpinner = (
    <div className="flex items-center justify-center h-full py-10">
      <div className="flex gap-1.5">
        {[0, 150, 300].map((d) => (
          <span key={d} className="w-1.5 h-1.5 rounded-full bg-slate-600 animate-bounce"
            style={{ animationDelay: `${d}ms` }} />
        ))}
      </div>
    </div>
  );

  // ── Left column: account selector list ─────────────────────────────────────
  const accountsList = (
    <div className="space-y-2">
      {/* "All Accounts" row — multi-account only */}
      {accounts.length > 1 && (
        <button
          onClick={() => { setSelectedId(null); setMobileTab("detail"); }}
          className={[
            "w-full text-left rounded-xl border px-3 py-2.5 transition-all duration-200",
            selectedId === null
              ? "border-slate-500/80 bg-slate-800/80 ring-1 ring-slate-500/20"
              : "border-slate-700/40 bg-slate-800/30 hover:bg-slate-800/60 hover:border-slate-600/50",
          ].join(" ")}
        >
          <div className="flex items-center justify-between gap-2">
            <div className="flex items-center gap-2 min-w-0">
              <Layers className="h-3.5 w-3.5 shrink-0 text-slate-400" />
              <span className="text-xs font-bold text-slate-300">All Accounts</span>
              {/* Colored dots */}
              <div className="flex -space-x-1 ml-1">
                {accounts.slice(0, 4).map((a) => (
                  <span key={a.id} className="w-2 h-2 rounded-full border border-slate-900 shrink-0"
                    style={{ backgroundColor: a.color }} />
                ))}
              </div>
            </div>
            <div className="flex items-center gap-2 shrink-0">
              <span className={`text-xs font-bold tabular-nums ${portfolioPL >= 0 ? "text-emerald-400" : "text-red-400"} ${b ? "blur-sm select-none" : ""}`}>
                {b ? rawFmt(portfolioPL, { sign: true }) : fmtMoney(portfolioPL, { sign: true })}
              </span>
              <ChevronRight
                className="h-3.5 w-3.5 transition-transform duration-200"
                style={{
                  color: selectedId === null ? "#94a3b8" : "#475569",
                  transform: selectedId === null ? "rotate(90deg)" : undefined,
                }}
              />
            </div>
          </div>
          {/* Portfolio balance — only when selected */}
          {selectedId === null && (
            <p className={`text-[10px] text-slate-500 mt-1 tabular-nums ${b ? "blur-sm select-none" : ""}`}>
              Balance: {b ? rawFmt(portfolioBalance) : fmtMoney(portfolioBalance)}
            </p>
          )}
        </button>
      )}

      {/* Per-account cards */}
      {loading ? loadingSpinner : accounts.map((account) => {
        const m = metricsMap[account.id];
        const isSel = selectedId === account.id;
        const plPos = m ? m.totalPL >= 0 : true;

        return (
          <button
            key={account.id}
            onClick={() => handleSelect(account.id)}
            className={[
              "w-full text-left rounded-xl border overflow-hidden transition-all duration-200",
              isSel
                ? "bg-slate-800/90 shadow-md"
                : "border-slate-700/50 bg-slate-800/40 hover:bg-slate-800/70 hover:border-slate-600/60",
            ].join(" ")}
            style={
              isSel
                ? { borderColor: account.color, borderLeftWidth: 3, boxShadow: `0 0 0 1px ${account.color}20` }
                : { borderLeftColor: account.color, borderLeftWidth: 3 }
            }
          >
            {/* Name + balance */}
            <div className="flex items-center justify-between px-3 pt-3 pb-2">
              <div className="flex items-center gap-2 min-w-0">
                <span className="w-2 h-2 rounded-full shrink-0" style={{ backgroundColor: account.color }} />
                <span className="text-sm font-bold text-white truncate">{account.name}</span>
                <span className="text-[10px] text-slate-600 shrink-0">{account.currency}</span>
