"use client";

import { ReactNode, useEffect } from "react";
import { usePathname, useRouter } from "next/navigation";
import { useUser } from "@/context/UserContext";
import { useSubscription } from "@/context/SubscriptionContext";

// Paths where the plan check is skipped (public / auth pages)
const PUBLIC_PATHS = [
  "/",
  "/login",
  "/pricing",
  "/checkout",
  "/plan-select",
  "/terms",
  "/privacy",
  "/refund",
  "/subscription",
];

function isPublicPath(pathname: string) {
  return (
    PUBLIC_PATHS.includes(pathname) ||
    pathname.startsWith("/auth/")
  );
}

export default function PlanGuard({ children }: { children: ReactNode }) {
  const { user, profile, loading } = useUser();
  const { hasAccess, isLoading } = useSubscription();
  const router = useRouter();
  const pathname = usePathname();

  useEffect(() => {
    if (loading || isLoading) return;
    if (!user) return;
    if (isPublicPath(pathname)) return;

    // New user — never selected a plan
    if (profile && profile.plan === null) {
      router.replace("/plan-select");
      return;
    }

    // Subscription expired or free plan
    if (!hasAccess) {
      router.replace("/pricing");
    }
  }, [loading, isLoading, user, profile, hasAccess, pathname, router]);

  return <>{children}</>;
}

Encontré el bug crítico. Está en `PlanGuard`, línea:

```ts
if (profile && profile.plan === null) {
  router.replace("/plan-select");
  return;
}
```

**El problema:** Esta condición se evalúa **antes** de la de `hasAccess`. Si `profile.plan` es `"pro"` (aunque esté expirado o sin fecha), **no entra** en esa rama, pasa directo a la verificación de `hasAccess`. Pero si `hasAccess` es `false`, debería redirigir a `/pricing`.

El bug real: **`hasAccess` depende del context, y el context aún puede estar cargando cuando la guard ya corrió**. Además, hay un problema de timing.

Voy a hacer el fix definitivo:

