import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@supabase/supabase-js";
import { createHmac, timingSafeEqual } from "crypto";

// Server-side Supabase client with service role (bypasses RLS)
const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

/**
 * Verifies the Paddle-Signature header using HMAC-SHA256.
 * Header format: "ts=<timestamp>;h1=<hex_signature>"
 */
function verifySignature(rawBody: string, header: string | null, secret: string): boolean {
  if (!header) return false;

  const parts: Record<string, string> = Object.fromEntries(
    header.split(";").map((p) => p.split("=") as [string, string])
  );
  const { ts, h1 } = parts;
  if (!ts || !h1) return false;

  const expected = createHmac("sha256", secret)
    .update(`${ts}:${rawBody}`)
    .digest("hex");

  try {
    return timingSafeEqual(Buffer.from(expected, "hex"), Buffer.from(h1, "hex"));
  } catch {
    return false;
  }
}

/**
 * Updates the user's plan in the user_profiles table.
 * Looks up by user_id (from customData) or falls back to email.
 */
async function updateUserPlan(
  userId: string | undefined,
  email: string | undefined,
  plan: string,
  expiresAt: string | null
) {
  const update = { plan, plan_expires_at: expiresAt, updated_at: new Date().toISOString() };

  if (userId) {
    const { error } = await supabase
      .from("user_profiles")
      .update(update)
      .eq("id", userId);
    if (error) throw new Error(`Supabase update failed: ${error.message}`);
    return;
  }

  // Fallback: look up by email via Supabase Auth admin API
  if (email) {
    const { data, error } = await supabase.auth.admin.listUsers({ perPage: 1000 });
    if (error) throw new Error(`Failed to list users: ${error.message}`);
    const authUser = data.users.find((u) => u.email === email);
    if (!authUser) throw new Error(`User not found for email: ${email}`);
    const { error: updateError } = await supabase
      .from("user_profiles")
      .update(update)
      .eq("id", authUser.id);
    if (updateError) throw new Error(`Supabase update failed: ${updateError.message}`);
  }
}

export async function POST(req: NextRequest) {
  const rawBody = await req.text();
  const signature = req.headers.get("Paddle-Signature");
  const webhookSecret = process.env.PADDLE_WEBHOOK_SECRET;

  // Verify signature when secret is configured
  if (webhookSecret) {
    if (!verifySignature(rawBody, signature, webhookSecret)) {
      console.error("Paddle webhook: invalid signature");
      return NextResponse.json({ error: "Invalid signature" }, { status: 401 });
    }
  }

  let event: { event_type: string; data: Record<string, any> };
  try {
    event = JSON.parse(rawBody);
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }

  const { event_type, data } = event;
  const userId: string | undefined = data.custom_data?.user_id;
  const email: string | undefined = data.customer?.email;

  console.log(`Paddle webhook: ${event_type}`, { userId, email });

  try {
    switch (event_type) {
      case "subscription.created":
      case "subscription.updated": {
        const status: string = data.status;

        // Fully canceled or paused — handle separately
        if (status === "canceled" || status === "paused") break;

        // Subscription is active but has a scheduled cancellation
        // Paddle sends subscription.updated with scheduled_change.action = "cancel"
        // In this case use the period end date as expiry so access ends correctly
        const scheduledCancel =
          data.scheduled_change?.action === "cancel"
            ? (data.scheduled_change?.effective_at ?? data.current_billing_period?.ends_at ?? null)
            : null;

        // Use next_billed_at as the expiry for active subscriptions
        // Add 1 day buffer so access doesn't expire before the charge processes
        const nextBilledAt: string | null = data.next_billed_at ?? null;
        let expiresAt: string | null = null;

        if (scheduledCancel) {
          // Has a pending cancel — expire at the end of the current period
          expiresAt = scheduledCancel;
        } else if (nextBilledAt) {
          const d = new Date(nextBilledAt);
          d.setDate(d.getDate() + 1);
          expiresAt = d.toISOString();
        } else {
          // No billing date available — use end of current period or revoke
          expiresAt = data.current_billing_period?.ends_at ?? null;
        }

        // If we still have no expiry date, don't grant open-ended pro access
        if (!expiresAt) {
          console.warn("Paddle webhook: no expiry date found for subscription, revoking access", { userId, email, status });
          await updateUserPlan(userId, email, "free", null);
          break;
        }

        await updateUserPlan(userId, email, "pro", expiresAt);
        break;
      }

      case "subscription.canceled": {
        // Subscription fully canceled.
        // Keep access until end of paid period if available (fair to the user).
        // Paddle usually provides current_billing_period.ends_at here.
        const endsAt: string | null =
          data.current_billing_period?.ends_at ??
          data.scheduled_change?.effective_at ??
          null;

        if (endsAt) {
          // Has remaining time — keep pro until period ends, then falls to free via planExpired check
          await updateUserPlan(userId, email, "pro", endsAt);
        } else {
          // No period info — revoke immediately
          await updateUserPlan(userId, email, "free", null);
        }
        break;
      }

      case "transaction.completed": {
        // Covers one-time payments and trial activations
        const periodEnd: string | null = data.billing_period?.ends_at ?? null;
        if (periodEnd) {
          await updateUserPlan(userId, email, "pro", periodEnd);
        }
        break;
      }

      default:
        // Unhandled event — acknowledge anyway
        break;
    }

    return NextResponse.json({ received: true });
  } catch (err) {
    console.error("Paddle webhook processing error:", err);
    return NextResponse.json({ error: "Webhook processing failed" }, { status: 500 });
  }
}

