    if (count === 0) console.warn(`updateUserPlan: no row found for userId=${userId}`);
    console.log("updateUserPlan: updated by userId", { userId, plan, expiresAt, count });
    return;
  }

  // Fallback: look up by email via Supabase Auth admin API
  if (email) {
    const { data, error } = await supabase.auth.admin.listUsers({ perPage: 1000 });
    if (error) throw new Error(`Failed to list users: ${error.message}`);
    const authUser = data.users.find((u) => u.email === email);
    if (!authUser) throw new Error(`User not found for email: ${email}`);
    const { error: updateError, count } = await supabase
      .from("user_profiles")
      .update(update)
      .eq("id", authUser.id)
      .select("id", { count: "exact", head: true });
    if (updateError) throw new Error(`Supabase update failed (email): ${updateError.message}`);
    console.log("updateUserPlan: updated by email", { email, authUserId: authUser.id, plan, expiresAt, count });
  }
}

