"use client";

import { createContext, useContext, useMemo, ReactNode } from "react";
import { useUser } from "@/context/UserContext";
import { BETA_MODE } from "@/lib/config";

type Plan = "beta" | "pro" | "free";

interface SubscriptionContextType {
  plan: Plan;
  isBeta: boolean;
  isPro: boolean;
  hasAccess: boolean; // true if user can use the app (beta OR pro)
  isLoading: boolean;
}

// Default is intentionally restrictive: deny access until profile loads.
// This prevents any flash of protected content during hydration.
const SubscriptionContext = createContext<SubscriptionContextType>({
  plan: "free",
  isBeta: false,
  isPro: false,
  hasAccess: false,
  isLoading: true,
});

export function SubscriptionProvider({ children }: { children: ReactNode }) {
  const { profile, loading } = useUser();

  const value = useMemo<SubscriptionContextType>(() => {
    // Still loading — deny access until we know the real state
    if (loading || profile === undefined) {
      return { plan: "free", isBeta: false, isPro: false, hasAccess: false, isLoading: true };
    }

    const planExpired = profile?.plan_expires_at
      ? new Date(profile.plan_expires_at) < new Date()
      : false;
    // "pro" without an expiry date is treated as free — inconsistent state
    const proWithoutExpiry = profile?.plan === "pro" && !profile?.plan_expires_at;
    // Resolve the actual plan from the DB, independent of BETA_MODE
    const resolvedPlan: Plan = (!profile?.plan || planExpired || proWithoutExpiry)
      ? "free"
      : (profile.plan as Plan);
    const isPro = resolvedPlan === "pro";
    const isBeta = resolvedPlan === "beta";
    // BETA_MODE gives access but does NOT change the displayed plan
    const hasAccess = BETA_MODE || isPro || isBeta;
    // Expose the real plan so the UI shows the correct badge
    return { plan: resolvedPlan, isBeta, isPro, hasAccess, isLoading: false };
  }, [profile, loading]);

  return (
    <SubscriptionContext.Provider value={value}>
      {children}
    </SubscriptionContext.Provider>
  );
}

export function useSubscription() {
  return useContext(SubscriptionContext);
}

