"use client";

import Script from "next/script";
import { PADDLE_CLIENT_TOKEN } from "@/lib/config";

/**
 * Loads the Paddle Billing v2 SDK and initializes it with the client token.
 * Using onLoad ensures Paddle.Initialize() runs only after the script is ready.
 */
export default function PaddleInit() {
  if (!PADDLE_CLIENT_TOKEN) return null;

  return (
    <Script
      src="https://cdn.paddle.com/paddle/v2/paddle.js"
      strategy="afterInteractive"
      onLoad={() => {
        // @ts-expect-error — Paddle JS loaded via script tag
        window.Paddle?.Initialize({ token: PADDLE_CLIENT_TOKEN });
      }}
    />
  );
}

