import { useState } from "react";
import Image from "next/image";
import Link from "next/link";
import {
  PLAN_PRICE_USD,
  PLAN_ORIGINAL_USD,
  PLAN_DISCOUNT_PCT,
  PLAN_PRICE_YEARLY_TOTAL,
  PLAN_PRICE_YEARLY_MONTHLY,
  PLAN_DISCOUNT_YEARLY_PCT,
  TRIAL_DAYS,
} from "@/lib/config";

const FEATURES = [
  "Unlimited manual trade entries",
  "Daily journal & emotion tracking",
  "Dashboard & calendar view",
  "Trading plan & rules tracking",
  "Deposits & withdrawals tracking",
  "Global leaderboard access",
  "Advanced analytics & charts",
  "Set Ups performance analysis",
  "Up to 3 trading accounts",
  "Priority support",
];

type BillingCycle = "monthly" | "yearly";

interface PricingPlansProps {
  ctaHref?: string;
  onCta?: (billing: BillingCycle) => void;
  ctaAsButton?: boolean;
  subheading?: string;
}

export default function PricingPlans({
  ctaHref = "/checkout",
  onCta,
  ctaAsButton = false,
  subheading,
}: PricingPlansProps) {
  const [billing, setBilling] = useState<BillingCycle>("yearly");

  const handleCta = () => {
    if (onCta) onCta(billing);
  };

  return (
    <>
      <style>{`
        @keyframes glowFloat {
          0%, 100% { opacity: 0.7; }
          50%       { opacity: 1;   }
        }
        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(12px); }
          to   { opacity: 1; transform: translateY(0);    }
        }
        .glow-float { animation: glowFloat 9s ease-in-out infinite; }
        .fade-in    { animation: fadeUp 0.45s 0.05s ease-out both; }
      `}</style>

      <main className="relative flex min-h-screen flex-col items-center justify-center px-4 py-12 overflow-hidden">

        {/* Background */}
        <div className="absolute inset-0 z-0">
          <Image
            src="/tradelab-wallpaper.png"
            alt=""
            fill
            className="object-cover"
            priority
            quality={100}
          />
          <div className="absolute inset-0 bg-slate-900/72 backdrop-blur-sm" />
        </div>

        {/* Atmospheric glow */}

