export default function CheckoutPage() {
  const { user } = useUser();
  const searchParams = useSearchParams();
  const billingParam = searchParams.get("billing");
  const isYearly = billingParam === "yearly";

  const priceId = isYearly ? PADDLE_YEARLY_PRICE_ID : PADDLE_PRICE_ID;
  const displayPrice = isYearly ? `$${PLAN_PRICE_YEARLY_MONTHLY}/mo` : `$${PLAN_PRICE_USD}/mo`;
  const displayTotal = isYearly ? `$${PLAN_PRICE_YEARLY_TOTAL}/year` : `$${PLAN_PRICE_USD}.00`;
  const displayOriginal = isYearly ? null : `$${PLAN_ORIGINAL_USD}.00/mo`;
  const discountLabel = isYearly ? `Save ${PLAN_DISCOUNT_YEARLY_PCT}%` : `Save ${PLAN_DISCOUNT_PCT}%`;

  const [code, setCode] = useState("");
  const [loading, setLoading] = useState(false);
  const [paddleReady, setPaddleReady] = useState(false);

  // Wait for Paddle to be ready
  useEffect(() => {
    const check = () => {
      // @ts-expect-error — Paddle JS loaded via script tag
      if (typeof window.Paddle !== "undefined") {
        setPaddleReady(true);
      }
    };
    check();
    const interval = setInterval(check, 300);
    const timeout = setTimeout(() => clearInterval(interval), 10000);
    return () => { clearInterval(interval); clearTimeout(timeout); };
  }, []);

  const handleSubscribe = async () => {
    if (!priceId) {
      alert("Paddle checkout is not configured yet. Contact support@tradelab.app to subscribe.");
      return;
    }

    setLoading(true);

    try {
      // Save affiliate code (fire-and-forget, non-blocking)
      if (user && code.trim()) {
        await saveAffiliateCode(user.id, code);
      }

      // @ts-expect-error — Paddle JS loaded via script tag
      if (typeof window.Paddle !== "undefined") {
        // @ts-expect-error — Paddle JS loaded via script tag
        window.Paddle.Checkout.open({
          items: [{ priceId, quantity: 1 }],
          customer: user?.email ? { email: user.email } : undefined,
          customData: {
            user_id: user?.id,
            ...(code.trim() ? { affiliate_code: code.trim().toUpperCase() } : {}),
          },
          settings: {
            successUrl: `${window.location.origin}/dashboard`,
          },
        });
        // Paddle opens an overlay — stop loading after a short delay
        setTimeout(() => setLoading(false), 1500);
      } else {
        // Fallback: redirect to Paddle hosted checkout
        window.location.href = `https://buy.paddle.com/product/${priceId}${user?.email ? `?customer_email=${encodeURIComponent(user.email)}` : ""}`;
        // Don't reset loading — navigating away
      }
    } catch (err) {
      console.error("Checkout error:", err);
      setLoading(false);
    }
  };

